CREATE OR REPLACE FUNCTION fpa_kep_ctrl_name ( as_salary_group char) RETURNS varchar AS $body$
DECLARE

ls_return varchar(400);

BEGIN

 if length(trim(both as_salary_group)) > 0 then
  select FPA_COM_GROUP_INITIAL(control_id) into STRICT ls_return
  from   sc_mem_m_ucf_member_group
  where  salary_group = as_salary_group;
 else
   ls_return := ' ';
 end if;

return ls_return;

Exception
 when others then CALL spa_dberror('FPA_KEP_CTRL_NAME');
END;
